1	/**
2	 * Integration tests for the Scheduler (src/server/scheduler/scheduler.ts).
3	 *
4	 * Uses real SQLite (with migrations) and stub ProcessManager / WorktreeManager
5	 * so no real git, worktrees, or agent processes are required.
6	 *
7	 * Coverage:
8	 *   AC-1  ingestWorkflow seeds workflow + item rows within the poll window.
9	 *   AC-2  Crash recovery transitions stale in_progress → awaiting_retry before
10	 *         any new items are scheduled.
11	 *   AC-3  Scheduler drives pending → ready → bootstrapping → in_progress →
12	 *         complete (or a terminal state) end-to-end for a single-phase workflow.
13	 *   AC-5  applyWorktreeCreated persists branch_name + worktree_path to workflows.
14	 *   AC-7  BroadcastFn is called with stream events forwarded from the parser.
15	 *   AC-8  stop() resolves after cancelling in-flight sessions (graceful drain).
16	 *   RC-5  Concurrency limit (maxParallel=1) prevents over-scheduling.
17	 *   RC-6  All production deps are injectable (verified by using stubs throughout).
18	 */
19	
20	import { describe, it, expect, beforeEach, afterEach } from 'vitest';
21	import { EventEmitter } from 'node:events';
22	import fs from 'node:fs';
23	import os from 'node:os';
24	import path from 'node:path';
25	import { fileURLToPath } from 'node:url';
26	import { openDbPool } from '../../src/server/storage/db.js';
27	import { applyMigrations } from '../../src/server/storage/migrate.js';
28	import type { DbPool } from '../../src/server/storage/db.js';
29	import type { ProcessManager, SpawnHandle, SpawnOpts } from '../../src/server/process/manager.js';
30	import type { WorktreeManager, WorktreeInfo, BootstrapEvent } from '../../src/server/worktree/manager.js';
31	import { Scheduler } from '../../src/server/scheduler/scheduler.js';
32	import { ingestWorkflow } from '../../src/server/scheduler/ingest.js';
33	import type { ResolvedConfig } from '../../src/shared/types/config.js';
