140	// Stub ProcessManager
141	// ---------------------------------------------------------------------------
142	
143	class StubProcessManager implements ProcessManager {
144	  readonly handles: StubSpawnHandle[] = [];
145	
146	  constructor(private readonly records: StubRecord[] = []) {}
147	
148	  async spawn(_opts: SpawnOpts): Promise<SpawnHandle> {
149	    const handle = new StubSpawnHandle(this.records);
150	    this.handles.push(handle);
151	    handle.start();
152	    return handle;
153	  }
154	}
