157	// Stub WorktreeManager (only implements the methods the scheduler calls)
158	// ---------------------------------------------------------------------------
159	
160	function makeWorktreeManager(opts: {
161	  worktreePath?: string;
162	  bootstrapEvent?: BootstrapEvent;
163	  failCreate?: boolean;
164	} = {}): WorktreeManager {
165	  const wt = opts.worktreePath ?? path.join(tmpDir, 'wt');
166	  fs.mkdirSync(wt, { recursive: true });
167	  return {
168	    async createWorktree(): Promise<WorktreeInfo> {
169	      if (opts.failCreate) throw new Error('createWorktree stub failure');
170	      return { branchName: 'yoke/test-abc123', worktreePath: wt };
171	    },
172	    async runBootstrap(): Promise<BootstrapEvent> {
173	      return opts.bootstrapEvent ?? { type: 'bootstrap_ok' };
174	    },
175	    // cleanup is never called by the scheduler directly
176	    async cleanup(): Promise<{ worktreeRemoved: boolean; branchRetained: boolean }> {
177	      return { worktreeRemoved: true, branchRetained: false };
178	    },
179	  } as unknown as WorktreeManager;
180	}
