182	// ---------------------------------------------------------------------------
183	// pollUntil — wait for a SQLite condition to become true
184	// ---------------------------------------------------------------------------
185	
186	async function pollUntil(
187	  check: () => boolean,
188	  { timeoutMs = 5000, intervalMs = 50 } = {},
189	): Promise<void> {
190	  const deadline = Date.now() + timeoutMs;
191	  while (Date.now() < deadline) {
192	    if (check()) return;
193	    await new Promise((r) => setTimeout(r, intervalMs));
194	  }
195	  throw new Error('pollUntil timed out');
196	}
