207	function buildScheduler(opts: {
208	  config?: ResolvedConfig;
209	  processManager?: ProcessManager;
210	  worktreeManager?: WorktreeManager;
211	  maxParallel?: number;
212	  pollIntervalMs?: number;
213	}): TestSchedulerResult {
214	  const broadcasts: TestSchedulerResult['broadcasts'] = [];
215	
216	  const scheduler = new Scheduler({
217	    db,
218	    config: opts.config ?? makeConfig(),
219	    processManager: opts.processManager ?? new StubProcessManager(),
220	    worktreeManager: opts.worktreeManager ?? makeWorktreeManager(),
221	    prepostRunner: async () => ({ kind: 'complete' }),
222	    assemblePrompt: async () => 'stub prompt',
223	    broadcast: (workflowId, sessionId, frameType, payload) => {
224	      broadcasts.push({ workflowId, sessionId, frameType, payload });
225	    },
226	    maxParallel: opts.maxParallel ?? 4,
227	    pollIntervalMs: opts.pollIntervalMs ?? 50,
228	    gracePeriodMs: 500,
229	  });
230	
231	  activeSchedulers.push(scheduler);
232	  return { scheduler, broadcasts };
233	}
