461	describe('AC-8: graceful drain on stop()', () => {
462	  it('resolves within gracePeriodMs even with a running session', async () => {
463	    const config = makeConfig();
464	
465	    // A process that never exits on its own — stalls until cancel() fires SIGTERM.
466	    class StallingPM implements ProcessManager {
467	      readonly handles: StubSpawnHandle[] = [];
468	      async spawn(_opts: SpawnOpts): Promise<SpawnHandle> {
469	        const handle = new StubSpawnHandle([]);
470	        // Override start() — do nothing. Only cancel() can unblock it.
471	        handle.start = () => { /* stall — never emit exit spontaneously */ };
472	        this.handles.push(handle);
473	        return handle;
474	      }
475	    }
476	    const pm = new StallingPM();
477	    const broadcasts: TestSchedulerResult['broadcasts'] = [];
478	    const sched = new Scheduler({
479	      db,
480	      config,
481	      processManager: pm,
482	      worktreeManager: makeWorktreeManager(),
483	      prepostRunner: async () => ({ kind: 'complete' }),
484	      assemblePrompt: async () => 'stub prompt',
485	      broadcast: (wid, sid, ft, p) => broadcasts.push({ workflowId: wid, sessionId: sid, frameType: ft, payload: p }),
486	      maxParallel: 4,
487	      pollIntervalMs: 50,
488	      gracePeriodMs: 1000,
489	    });
490	    activeSchedulers.push(sched);
491	
492	    await sched.start();
493	
494	    // Wait for at least one spawn (handle appears in pm.handles).
495	    await pollUntil(() => (pm as StallingPM).handles.length > 0, { timeoutMs: 10_000 });
496	
497	    const t0 = Date.now();
498	    await sched.stop();
499	    const elapsed = Date.now() - t0;
500	
501	    // Should complete within gracePeriodMs + generous buffer.
502	    expect(elapsed).toBeLessThan(3000);
503	  });
504	});
