510	describe('RC-5: concurrency limit', () => {
511	  it('does not spawn more sessions than maxParallel', async () => {
512	    // Two stages, maxParallel=1 → only 1 session at a time.
513	    const config = makeConfig({
514	      pipeline: {
515	        stages: [
516	          { id: 's1', run: 'once', phases: ['phase-one'] },
517	          { id: 's2', run: 'once', phases: ['phase-one'] },
518	        ],
519	      },
520	    });
521	
522	    // Track concurrent spawn calls.
523	    let maxConcurrent = 0;
524	    let current = 0;
525	
526	    class CountingPM implements ProcessManager {
527	      async spawn(_opts: SpawnOpts): Promise<SpawnHandle> {
528	        current++;
529	        if (current > maxConcurrent) maxConcurrent = current;
530	
531	        const handle = new StubSpawnHandle([{ type: 'exit', code: 0 }]);
532	        handle.on('exit', () => { current--; });
533	        handle.start();
534	        return handle;
535	      }
536	    }
537	
538	    const { scheduler } = buildScheduler({
539	      config,
540	      processManager: new CountingPM(),
541	      maxParallel: 1,
542	      pollIntervalMs: 50,
543	    });
544	
545	    await scheduler.start();
546	    const workflowId = scheduler.workflowId!;
547	
548	    await pollUntil(() => {
549	      const wf = db.reader()
550	        .prepare('SELECT status FROM workflows WHERE id = ?')
551	        .get(workflowId) as { status: string } | undefined;
552	      return wf?.status === 'completed';
553	    }, { timeoutMs: 15_000 });
554	
555	    expect(maxConcurrent).toBeLessThanOrEqual(1);
556	
557	    await scheduler.stop();
558	  });
559	});
