174	// ---------------------------------------------------------------------------
175	// Scheduler
176	// ---------------------------------------------------------------------------
177	
178	export class Scheduler {
179	  private readonly db: DbPool;
180	  private readonly config: ResolvedConfig;
181	  private readonly processManager: ProcessManager;
182	  private readonly worktreeManager: WorktreeManager;
183	  private readonly prepostRunner: PrePostRunnerFn;
184	  private readonly assemblePromptFn: PromptAssemblerFn;
185	  private readonly broadcastFn: BroadcastFn;
186	  private readonly pollIntervalMs: number;
187	  private readonly gracePeriodMs: number;
188	  private readonly maxParallel: number;
189	
190	  /** workflowId populated by start(). */
191	  workflowId: string | null = null;
192	
193	  /** Items currently being managed (bootstrapping, spawning, or running). */
194	  private readonly inFlight = new Map<string, InFlightEntry>();
195	
196	  /** itemId → timestamp(ms) when the item may next be retried. */
197	  private readonly retryAfterAt = new Map<string, number>();
198	
199	  /** itemId → unix seconds when rate-limit window resets. */
200	  private readonly rateLimitResetAt = new Map<string, number>();
201	
202	  private pollTimer: ReturnType<typeof setTimeout> | null = null;
203	  private stopped = false;
204	
205	  constructor(opts: SchedulerOpts) {
206	    this.db = opts.db;
207	    this.config = opts.config;
208	    this.processManager = opts.processManager;
209	    this.worktreeManager = opts.worktreeManager;
210	    this.prepostRunner = opts.prepostRunner;
211	    this.assemblePromptFn = opts.assemblePrompt;
212	    this.broadcastFn = opts.broadcast;
213	    this.pollIntervalMs = opts.pollIntervalMs ?? DEFAULT_POLL_INTERVAL_MS;
214	    this.gracePeriodMs = opts.gracePeriodMs ?? DEFAULT_GRACE_PERIOD_MS;
215	    this.maxParallel = opts.maxParallel ?? DEFAULT_MAX_PARALLEL;
216	  }
217	
218	  // -------------------------------------------------------------------------
219	  // start — AC-1
220	  // -------------------------------------------------------------------------
221	
222	  /**
223	   * Ingests the workflow, runs crash recovery, and starts the scheduling loop.
224	   * Returns once the first tick has been queued (not waited for).
225	   */
226	  async start(): Promise<void> {
227	    if (this.stopped) throw new Error('Scheduler already stopped');
228	
229	    // Step 1: Ingest workflow + items from config (AC-1).
230	    const { workflowId } = ingestWorkflow(this.db, this.config);
231	    this.workflowId = workflowId;
232	
233	    // Step 2: Crash recovery — detect stale sessions from a previous run (RC-4).
234	    const recoveryInfos = buildCrashRecovery(this.db);
235	    for (const info of recoveryInfos) {
236	      // Transition stale in_progress items to awaiting_retry or awaiting_user
237	      // so they are not double-spawned (RC-4: stale sessions ≠ live sessions).
238	      for (const stale of info.staleSessions) {
239	        if (!stale.itemId) continue;
240	        const item = this._readItem(stale.itemId);
241	        if (!item || item.status !== 'in_progress') continue;
242	        // Fire session_fail with unknown classifier → awaiting_user or awaiting_retry
243	        // (budget-dependent). The user or auto-resume will restart the item.
244	        applyItemTransition({
245	          db: this.db,
246	          workflowId: info.workflowId,
247	          itemId: stale.itemId,
248	          sessionId: stale.sessionId,
249	          stage: item.stage_id,
250	          phase: item.current_phase ?? '',
251	          attempt: item.retry_count + 1,
252	          event: 'session_fail',
253	          guardCtx: { classifierResult: 'unknown' },
254	        });
255	      }
256	    }
257	
258	    // Step 3: Start the poll loop (AC-1: scheduling begins within 2 s).
259	    this._scheduleTick();
260	  }
261	
262	  // -------------------------------------------------------------------------
263	  // stop — AC-8 (graceful drain)
264	  // -------------------------------------------------------------------------
265	
266	  /**
267	   * Stops the poll loop and cancels all in-flight sessions.
268	   *
269	   * Sends SIGTERM to each session's process group, waits up to gracePeriodMs
270	   * for natural exit, then forces SIGKILL via cancel(). Returns after all
271	   * in-flight sessions are cancelled (or the grace period expires).
272	   */
273	  async stop(): Promise<void> {
274	    this.stopped = true;
275	    if (this.pollTimer !== null) {
276	      clearTimeout(this.pollTimer);
277	      this.pollTimer = null;
278	    }
279	
280	    // Cancel all in-flight sessions and collect their exit promises.
281	    const drainPromises: Promise<void>[] = [];
282	    for (const [, entry] of this.inFlight) {
283	      if (entry !== 'pending' && entry.handle) {
284	        drainPromises.push(entry.handle.cancel());
285	      }
286	    }
287	
288	    // Wait for all cancellations with overall timeout.
289	    await Promise.race([
290	      Promise.allSettled(drainPromises),
291	      new Promise<void>((resolve) => setTimeout(resolve, this.gracePeriodMs)),
292	    ]);
293	  }
294	
295	  // -------------------------------------------------------------------------
296	  // Tick loop
297	  // -------------------------------------------------------------------------
298	
299	  private _scheduleTick(): void {

300	    if (this.stopped) return;
301	    this.pollTimer = setTimeout(() => {
302	      void this._tick();
303	    }, this.pollIntervalMs);
304	  }
305	
306	  private async _tick(): Promise<void> {
307	    if (this.stopped) return;
308	    try {
309	      await this._processWorkflows();
310	    } catch (err) {
311	      // Tick errors must not crash the loop.
312	      console.error('[scheduler] tick error:', err);
313	    } finally {
314	      if (!this.stopped) this._scheduleTick();
315	    }
316	  }
317	
318	  // -------------------------------------------------------------------------
319	  // _processWorkflows — RC-1: re-read SQLite on every tick
320	  // -------------------------------------------------------------------------
321	
322	  private async _processWorkflows(): Promise<void> {
323	    const placeholders = TERMINAL_WF_STATUSES.map(() => '?').join(',');
324	    const workflows = this.db.reader()
325	      .prepare(
326	        `SELECT id, name, status, current_stage, worktree_path, branch_name
327	           FROM workflows
328	          WHERE status NOT IN (${placeholders})`,
329	      )
330	      .all(...TERMINAL_WF_STATUSES) as WorkflowDbRow[];
331	
332	    for (const wf of workflows) {
333	      await this._processWorkflow(wf);
334	    }
335	  }
336	
337	  private async _processWorkflow(wf: WorkflowDbRow): Promise<void> {
338	    // RC-5: count running sessions from SQLite + pending spawns in inFlight.
339	    const runningSql = this.db.reader()
340	      .prepare(
341	        `SELECT COUNT(*) AS cnt FROM sessions
342	          WHERE workflow_id = ? AND status = 'running'`,
343	      )
344	      .get(wf.id) as { cnt: number };
345	
346	    // Items currently in inFlight count as running even if insertSession hasn't
347	    // been called yet — prevents over-scheduling within a single tick.
348	    const pendingInFlight = [...this.inFlight.keys()].filter((id) => {
349	      const item = this._readItem(id);
350	      return item?.workflow_id === wf.id;
351	    }).length;
352	
353	    let effectiveRunning = runningSql.cnt + pendingInFlight;
354	
355	    const items = this._readWorkflowItems(wf.id);
356	
357	    for (const item of items) {
358	      switch (item.status) {
359	        // ------------------------------------------------------------------
360	        // pending → try deps_satisfied
361	        // ------------------------------------------------------------------
362	        case 'pending': {
363	          const result = applyItemTransition({
364	            db: this.db,
365	            workflowId: wf.id,
366	            itemId: item.id,
367	            sessionId: null,
368	            stage: item.stage_id,
369	            phase: item.current_phase ?? '',
370	            attempt: item.retry_count + 1,
371	            event: 'deps_satisfied',
372	          });
373	          // Only broadcast if the state actually changed.
374	          if (result.newState !== 'pending') {
375	            this._broadcastItemState(wf.id, item.id, item.stage_id, result);
376	          }
377	          break;
378	        }
379	
380	        // ------------------------------------------------------------------
381	        // ready → phase_start → bootstrapping | in_progress
382	        // ------------------------------------------------------------------
383	        case 'ready': {
384	          if (effectiveRunning >= this.maxParallel) break;
385	          if (this.inFlight.has(item.id)) break;
386	
387	          const stage = this._findStage(item.stage_id);
388	          if (!stage) break;
389	
390	          const phaseIdx = stage.phases.indexOf(item.current_phase ?? '');
391	          const morePhases = phaseIdx >= 0 && phaseIdx < stage.phases.length - 1;
392	          const nextPhase = morePhases ? stage.phases[phaseIdx + 1] : undefined;
393	
394	          const result = applyItemTransition({
395	            db: this.db,
396	            workflowId: wf.id,
397	            itemId: item.id,
398	            sessionId: null,
399	            stage: item.stage_id,
400	            phase: item.current_phase ?? '',
401	            attempt: item.retry_count + 1,
402	            event: 'phase_start',
403	            guardCtx: { morePhases, nextPhase },
404	          });
405	          this._broadcastItemState(wf.id, item.id, item.stage_id, result);
406	
407	          if (result.newState === 'bootstrapping') {
408	            this.inFlight.set(item.id, 'pending');
409	            effectiveRunning++;
410	            void this._doBootstrapThenSpawn(wf, item, stage);
411	          } else if (result.newState === 'in_progress') {
412	            this.inFlight.set(item.id, 'pending');
413	            effectiveRunning++;
414	            void this._runSession(wf, this._readItem(item.id) ?? item, stage);
415	          }
416	          break;
417	        }
418	
419	        // ------------------------------------------------------------------
420	        // in_progress without an active session → spawn (crash resume path)
421	        // ------------------------------------------------------------------
422	        case 'in_progress': {
423	          if (this.inFlight.has(item.id)) break;
424	          if (effectiveRunning >= this.maxParallel) break;
425	
426	          const stage = this._findStage(item.stage_id);
427	          if (!stage) break;
428	
429	          this.inFlight.set(item.id, 'pending');
430	          effectiveRunning++;
431	          void this._runSession(wf, item, stage);
432	          break;
433	        }
434	
435	        // ------------------------------------------------------------------
436	        // awaiting_retry → fire backoff_elapsed after RETRY_BACKOFF_MS
437	        // ------------------------------------------------------------------
438	        case 'awaiting_retry': {
439	          // Arm a retry timer if not already set.
440	          if (!this.retryAfterAt.has(item.id)) {
441	            this.retryAfterAt.set(item.id, Date.now() + RETRY_BACKOFF_MS);
442	          }
443	          const retryAt = this.retryAfterAt.get(item.id)!;
444	          if (Date.now() < retryAt) break;
445	
446	          const result = applyItemTransition({
447	            db: this.db,
448	            workflowId: wf.id,
449	            itemId: item.id,

450	            sessionId: null,
451	            stage: item.stage_id,
452	            phase: item.current_phase ?? '',
453	            attempt: item.retry_count + 1,
454	            event: 'backoff_elapsed',
455	          });
456	          this._broadcastItemState(wf.id, item.id, item.stage_id, result);
457	          this.retryAfterAt.delete(item.id);
458	          break;
459	        }
460	
461	        // ------------------------------------------------------------------
462	        // rate_limited → fire rate_limit_window_elapsed after reset_at
463	        // ------------------------------------------------------------------
464	        case 'rate_limited': {
465	          const resetAt = this.rateLimitResetAt.get(item.id);
466	          // If reset_at is unknown (scheduler restart), fire immediately.
467	          if (resetAt !== undefined && Date.now() < resetAt * 1000) break;
468	
469	          const result = applyItemTransition({
470	            db: this.db,
471	            workflowId: wf.id,
472	            itemId: item.id,
473	            sessionId: null,
474	            stage: item.stage_id,
475	            phase: item.current_phase ?? '',
476	            attempt: item.retry_count + 1,
477	            event: 'rate_limit_window_elapsed',
478	          });
479	          this._broadcastItemState(wf.id, item.id, item.stage_id, result);
480	          this.rateLimitResetAt.delete(item.id);
481	          break;
482	        }
483	
484	        default:
485	          // blocked, abandoned, complete, bootstrap_failed, awaiting_user:
486	          // terminal or requires user action — skip silently.
487	          break;
488	      }
489	    }
490	  }
