492	  // -------------------------------------------------------------------------
493	  // _doBootstrapThenSpawn — worktree creation + bootstrap commands
494	  // -------------------------------------------------------------------------
495	
496	  private async _doBootstrapThenSpawn(
497	    wf: WorkflowDbRow,
498	    item: ItemRow,
499	    stage: Stage,
500	  ): Promise<void> {
501	    if (this.stopped) {
502	      this.inFlight.delete(item.id);
503	      return;
504	    }
505	    try {
506	      // --- Create worktree if not already present (first phase of first stage).
507	      let worktreePath = wf.worktree_path;
508	      if (!worktreePath) {
509	        const baseDir = this.config.worktrees?.base_dir
510	          ? path.resolve(this.config.configDir, this.config.worktrees.base_dir)
511	          : path.join(this.config.configDir, '.worktrees');
512	
513	        let wtInfo: { branchName: string; worktreePath: string };
514	        try {
515	          wtInfo = await this.worktreeManager.createWorktree({
516	            workflowId: wf.id,
517	            workflowName: wf.name,
518	            baseDir,
519	            branchPrefix: this.config.worktrees?.branch_prefix ?? 'yoke/',
520	          });
521	        } catch {
522	          // Worktree creation failed → bootstrap_fail (triggers pending_attention).
523	          const result = applyItemTransition({
524	            db: this.db,
525	            workflowId: wf.id,
526	            itemId: item.id,
527	            sessionId: null,
528	            stage: item.stage_id,
529	            phase: item.current_phase ?? '',
530	            attempt: item.retry_count + 1,
531	            event: 'bootstrap_fail',
532	          });
533	          this._broadcastItemState(wf.id, item.id, item.stage_id, result);
534	          this.inFlight.delete(item.id);
535	          return;
536	        }
537	
538	        // Persist worktree info into SQLite (RC-2: through engine function).
539	        applyWorktreeCreated({
540	          db: this.db,
541	          workflowId: wf.id,
542	          branchName: wtInfo.branchName,
543	          worktreePath: wtInfo.worktreePath,
544	        });
545	        worktreePath = wtInfo.worktreePath;
546	      }
547	
548	      // --- Run bootstrap commands.
549	      const commands = this.config.worktrees?.bootstrap?.commands ?? [];
550	      const bootstrapEvent = await this.worktreeManager.runBootstrap({
551	        worktreePath,
552	        commands,
553	      });
554	
555	      const result = applyItemTransition({
556	        db: this.db,
557	        workflowId: wf.id,
558	        itemId: item.id,
559	        sessionId: null,
560	        stage: item.stage_id,
561	        phase: item.current_phase ?? '',
562	        attempt: item.retry_count + 1,
563	        event: bootstrapEvent.type,
564	      });
565	      this._broadcastItemState(wf.id, item.id, item.stage_id, result);
566	
567	      if (result.newState === 'in_progress') {
568	        // Bootstrap succeeded — continue to session spawn without a tick delay.
569	        const freshItem = this._readItem(item.id);
570	        if (freshItem) {
571	          const freshWf = this._readWorkflow(wf.id);
572	          if (freshWf) {
573	            await this._runSession(freshWf, freshItem, stage);
574	            return;
575	          }
576	        }
577	      }
578	    } catch (err) {
579	      console.error(`[scheduler] bootstrap error for item ${item.id}:`, err);
580	    }
581	    this.inFlight.delete(item.id);
582	  }
583	
584	  // -------------------------------------------------------------------------
585	  // _runSession — full async session lifecycle for one item phase
586	  // -------------------------------------------------------------------------
587	
588	  private async _runSession(
589	    wf: WorkflowDbRow,
590	    item: ItemRow,
591	    stage: Stage,
592	  ): Promise<void> {
593	    if (this.stopped) {
594	      this.inFlight.delete(item.id);
595	      return;
596	    }
597	
598	    const phaseKey = item.current_phase ?? stage.phases[0] ?? '';
599	    const phaseConfig = this.config.phases[phaseKey];

600	
601	    if (!phaseConfig) {
602	      console.error(
603	        `[scheduler] phase config not found for '${phaseKey}' in item ${item.id}`,
604	      );
605	      this.inFlight.delete(item.id);
606	      return;
607	    }
608	
609	    const sessionId = crypto.randomUUID();
610	    const attempt = item.retry_count + 1;
611	
612	    // Correlation env injected into all child processes.
613	    const correlationEnv: Record<string, string> = {
614	      YOKE_WORKFLOW_ID: wf.id,
615	      YOKE_ITEM_ID: item.id,
616	      YOKE_STAGE: item.stage_id,
617	      YOKE_PHASE: phaseKey,
618	      YOKE_SESSION_ID: sessionId,
619	      YOKE_ATTEMPT: String(attempt),
620	    };
621	
622	    const worktreePath = wf.worktree_path ?? this.config.configDir;
623	
624	    // RC-2: insertSession via engine helper (not db.writer directly).
625	    // Inserted BEFORE spawn so SQLite concurrency count is immediately accurate.
626	    insertSession(this.db, {
627	      sessionId,
628	      workflowId: wf.id,
629	      itemId: item.id,
630	      stage: item.stage_id,
631	      phase: phaseKey,
632	      pid: null,
633	      pgid: null,
634	    });
635	
636	    // Open session log — writes session_log_path to SQLite then opens the file.
637	    const { writer: logWriter } = await openSessionLog(this.db, {
638	      configDir: this.config.configDir,
639	      workflowId: wf.id,
640	      sessionId,
641	    });
642	
643	    // --- Pre: commands (AC-4) ---
644	    if (phaseConfig.pre && phaseConfig.pre.length > 0) {
645	      const preResult = await this.prepostRunner({
646	        commands: phaseConfig.pre,
647	        worktreePath,
648	        logWriter,
649	        when: 'pre',
650	        env: correlationEnv,
651	      });
652	
653	      if (preResult.kind !== 'complete') {
654	        // Pre-command blocked spawn.
655	        const preAction = preResult.kind === 'action'
656	          ? (preResult.action === 'stop-and-ask' ? 'stop-and-ask' as const : 'fail' as const)
657	          : 'fail' as const;
658	
659	        const result = applyItemTransition({
660	          db: this.db,
661	          workflowId: wf.id,
662	          itemId: item.id,
663	          sessionId,
664	          stage: item.stage_id,
665	          phase: phaseKey,
666	          attempt,
667	          event: 'pre_command_failed',
668	          guardCtx: { preCommandAction: preAction },
669	        });
670	        this._broadcastItemState(wf.id, item.id, item.stage_id, result);
671	        await logWriter.close();
672	        endSession(this.db, sessionId, { exitCode: null });
673	        this.inFlight.delete(item.id);
674	        return;
675	      }
676	    }
677	
678	    // --- Assemble prompt (AC-3) ---
679	    let promptText: string;
680	    try {
681	      promptText = await this.assemblePromptFn({
682	        worktreePath,
683	        phaseConfig,
684	        workflowId: wf.id,
685	        workflowName: wf.name,
686	        stageId: item.stage_id,
687	        stageRun: stage.run,
688	        itemId: item.id,
689	        itemData: item.data,
690	        itemStatus: item.status,
691	        itemCurrentPhase: item.current_phase,
692	        itemRetryCount: item.retry_count,
693	        itemBlockedReason: item.blocked_reason,
694	      });
695	    } catch (err) {
