322	  private async _processWorkflows(): Promise<void> {
323	    const placeholders = TERMINAL_WF_STATUSES.map(() => '?').join(',');
324	    const workflows = this.db.reader()
325	      .prepare(
326	        `SELECT id, name, status, current_stage, worktree_path, branch_name
327	           FROM workflows
328	          WHERE status NOT IN (${placeholders})`,
329	      )
330	      .all(...TERMINAL_WF_STATUSES) as WorkflowDbRow[];
