446	          const result = applyItemTransition({
447	            db: this.db,
448	            workflowId: wf.id,
449	            itemId: item.id,
450	            sessionId: null,
451	            stage: item.stage_id,
452	            phase: item.current_phase ?? '',
453	            attempt: item.retry_count + 1,
454	            event: 'backoff_elapsed',
455	          });
456	          this._broadcastItemState(wf.id, item.id, item.stage_id, result);
457	          this.retryAfterAt.delete(item.id);
458	          break;
459	        }
460	
461	        // ------------------------------------------------------------------
462	        // rate_limited → fire rate_limit_window_elapsed after reset_at
463	        // ------------------------------------------------------------------
464	        case 'rate_limited': {
465	          const resetAt = this.rateLimitResetAt.get(item.id);
466	          // If reset_at is unknown (scheduler restart), fire immediately.
467	          if (resetAt !== undefined && Date.now() < resetAt * 1000) break;
