101	class StubSpawnHandle extends EventEmitter implements SpawnHandle {
102	  readonly pid = 99001;
103	  readonly pgid = 99001;
104	  private _alive = true;
105	
106	  constructor(private readonly records: StubRecord[] = []) {
107	    super();
108	  }
109	
110	  isAlive(): boolean { return this._alive; }
111	
112	  async cancel(): Promise<void> {
113	    this._alive = false;
114	    setImmediate(() => this.emit('exit', null, 'SIGTERM'));
115	  }
