117	  start(): void {
118	    const records = this.records;
119	    let i = 0;
120	    const emit = () => {
121	      if (!this._alive || i >= records.length) {
122	        if (this._alive) { this._alive = false; this.emit('exit', 0, null); }
123	        return;
124	      }
125	      const rec = records[i++];
126	      if (rec.type === 'stdout') this.emit('stdout_line', rec.line);
127	      else if (rec.type === 'stderr') this.emit('stderr_data', rec.chunk);
128	      else if (rec.type === 'exit') {
129	        this._alive = false;
130	        this.emit('exit', rec.code, null);
131	        return;
132	      }
133	      setImmediate(emit);
134	    };
