466	    class StallingPM implements ProcessManager {
467	      readonly handles: StubSpawnHandle[] = [];
468	      async spawn(_opts: SpawnOpts): Promise<SpawnHandle> {
469	        const handle = new StubSpawnHandle([]);
470	        // Override start() — do nothing. Only cancel() can unblock it.
471	        handle.start = () => { /* stall — never emit exit spontaneously */ };
