517	          { id: 's2', run: 'once', phases: ['phase-one'] },
518	        ],
519	      },
520	    });
521	
522	    // Track concurrent spawn calls.
523	    let maxConcurrent = 0;
524	    let current = 0;
525	
526	    class CountingPM implements ProcessManager {
527	      async spawn(_opts: SpawnOpts): Promise<SpawnHandle> {
528	        current++;
529	        if (current > maxConcurrent) maxConcurrent = current;
530	
531	        const handle = new StubSpawnHandle([{ type: 'exit', code: 0 }]);
532	        handle.on('exit', () => { current--; });
533	        handle.start();
534	        return handle;
535	      }
536	    }
537	
538	    const { scheduler } = buildScheduler({
539	      config,
540	      processManager: new CountingPM(),
541	      maxParallel: 1,
542	      pollIntervalMs: 50,
543	    });
544	
545	    await scheduler.start();
546	    const workflowId = scheduler.workflowId!;
547	
