551	        .get(workflowId) as { status: string } | undefined;
552	      return wf?.status === 'completed';
553	    }, { timeoutMs: 15_000 });
554	
555	    expect(maxConcurrent).toBeLessThanOrEqual(1);
556	
557	    await scheduler.stop();
558	  });
559	});
