describe('session_fail — policy classifier', () => {
  it('policy classifier → awaiting_user with no retry (same as unknown)', () => {
    const wfId = makeWfId();
    const itemId = makeItemId();
    insertWorkflow(wfId);
    insertItem(itemId, wfId, 'stage1', { status: 'in_progress', retryCount: 0 });

